#include <bits/stdc++.h>
using namespace std;

const int N=4e5+10;

int last=1,tot=1;
long long f[N],sum[N],ans;
char s[N];
vector<int> e[N];

struct Node{
    int son[26],len,fa;
}st[N];

void extend(int c){
    int p=last,np=++tot;
    last=np;
    f[tot]=1;
    st[np].len=st[p].len+1;
    for(;p && !st[p].son[c];p=st[p].fa) st[p].son[c]=np;
    if(!p){
        st[np].fa=1;
        return;
    }
    int q=st[p].son[c];
    if(st[q].len==st[p].len+1)
        st[np].fa=q;
    else{
        int nq=++tot;
        st[nq]=st[q],st[nq].len=st[p].len+1;
        st[q].fa=st[np].fa=nq;
        for(;p && st[p].son[c]==q;p=st[p].fa) st[p].son[c]=nq;
    }
}

void dfs(int x){
    for(int y:e[x]){
        dfs(y);
        f[x]+=f[y];
    }
}

void dfs2(int x){
    sum[x]+=f[x]*(st[x].len-st[st[x].fa].len);
    for(int y:e[x]){
        sum[y]+=sum[x];
        dfs2(y);
    }
}

int main(){
    scanf("%s",s);
    for(int i=0;s[i];i++) extend(s[i]-'a');
    for(int i=2;i<=tot;i++) e[st[i].fa].push_back(i);
    dfs(1);
    dfs2(1);
    scanf("%s",s);
    for(int i=0,p=1,len=0;s[i];i++){
        int c=s[i]-'a';
        while(p>1 && !st[p].son[c]) p=st[p].fa,len=st[p].len;
        if(st[p].son[c]) p=st[p].son[c],len++;
        ans+=sum[st[p].fa]+f[p]*(len-st[st[p].fa].len);
    }
    printf("%lld",ans);
    return 0;
}
